// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * LinearVestingVault
 * - Holds ERC20 tokens
 * - Releases to beneficiary after a cliff, linearly over `duration`
 *
 * Terms:
 * - start: vesting start timestamp
 * - cliffSeconds: nothing is claimable before start + cliffSeconds
 * - durationSeconds: total time from start to fully vested (must be >= cliffSeconds)
 *   - linear vesting starts after the cliff and lasts (durationSeconds - cliffSeconds)
 */

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract LinearVestingVault {
  IERC20 public immutable token;
  address public immutable beneficiary;
  uint64 public immutable start;
  uint64 public immutable cliffSeconds;
  uint64 public immutable durationSeconds;
  uint256 public immutable totalAllocation;

  uint256 public released;

  event Released(uint256 amount);

  constructor(
    address token_,
    address beneficiary_,
    uint64 start_,
    uint64 cliffSeconds_,
    uint64 durationSeconds_,
    uint256 totalAllocation_
  ) {
    require(token_ != address(0), "token=0");
    require(beneficiary_ != address(0), "beneficiary=0");
    require(durationSeconds_ > 0, "duration=0");
    require(durationSeconds_ >= cliffSeconds_, "duration < cliff");
    require(totalAllocation_ > 0, "allocation=0");

    token = IERC20(token_);
    beneficiary = beneficiary_;
    start = start_;
    cliffSeconds = cliffSeconds_;
    durationSeconds = durationSeconds_;
    totalAllocation = totalAllocation_;
  }

  function vestedAmount(uint64 timestamp) public view returns (uint256) {
    uint64 cliffTime = start + cliffSeconds;
    if (timestamp < cliffTime) return 0;

    uint64 endTime = start + durationSeconds;
    if (timestamp >= endTime) return totalAllocation;

    // Flow #1: linear vesting starts AFTER the cliff, so the vested amount at cliffTime is 0 (no jump).
    uint256 linearDuration = uint256(durationSeconds - cliffSeconds);
    if (linearDuration == 0) return totalAllocation;
    uint256 elapsedSinceCliff = uint256(timestamp - cliffTime);
    return (totalAllocation * elapsedSinceCliff) / linearDuration;
  }

  function releasable() public view returns (uint256) {
    uint256 vested = vestedAmount(uint64(block.timestamp));
    if (vested <= released) return 0;
    return vested - released;
  }

  function release() external {
    require(msg.sender == beneficiary, "not beneficiary");
    uint256 amount = releasable();
    require(amount > 0, "nothing to release");
    released += amount;
    bool ok = token.transfer(beneficiary, amount);
    require(ok, "transfer failed");
    emit Released(amount);
  }
}

contracts/launch/LinearVestingVaultUpgra.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * LinearVestingVaultUpgradeable (clone-friendly)
 * - Holds ERC20 tokens
 * - Releases to beneficiary after a cliff, then linearly until fully vested at `start + duration`
 * - Uses initializer instead of constructor (for EIP-1167 clones)
 */

import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract LinearVestingVaultUpgradeable is Initializable {
  IERC20 public token;
  address public beneficiary;
  uint64 public start;
  uint64 public cliffSeconds;
  uint64 public durationSeconds;
  uint256 public totalAllocation;

  uint256 public released;

  event Released(uint256 amount, uint256 totalReleased, uint256 remaining);

  function initialize(
    address token_,
    address beneficiary_,
    uint64 start_,
    uint64 cliffSeconds_,
    uint64 durationSeconds_,
    uint256 totalAllocation_
  ) external initializer {
    require(token_ != address(0), "token=0");
    require(beneficiary_ != address(0), "beneficiary=0");
    require(durationSeconds_ > 0, "duration=0");
    require(durationSeconds_ >= cliffSeconds_, "duration < cliff");
    require(totalAllocation_ > 0, "allocation=0");

    token = IERC20(token_);
    beneficiary = beneficiary_;
    start = start_;
    cliffSeconds = cliffSeconds_;
    durationSeconds = durationSeconds_;
    totalAllocation = totalAllocation_;
  }

  function vestedAmount(uint64 timestamp) public view returns (uint256) {
    uint64 cliffTime = start + cliffSeconds;
    if (timestamp < cliffTime) return 0;

    uint64 endTime = start + durationSeconds;
    if (timestamp >= endTime) return totalAllocation;

    // Flow #1: linear vesting starts AFTER the cliff, so the vested amount at cliffTime is 0 (no jump).
    uint256 linearDuration = uint256(durationSeconds - cliffSeconds);
    if (linearDuration == 0) return totalAllocation;
    uint256 elapsedSinceCliff = uint256(timestamp - cliffTime);

    // Calculate vested amount
    uint256 vested = (totalAllocation * elapsedSinceCliff) / linearDuration;

    // If we're very close to the end, return totalAllocation to avoid precision loss
    // This ensures all tokens can be released eventually
    if (elapsedSinceCliff + 1 >= linearDuration) {
      return totalAllocation;
    }

    return vested;
  }

  function releasable() public view returns (uint256) {
    // block.timestamp is uint256, but vestedAmount accepts uint64
    // In practice, uint64 is sufficient until year 2106
    require(block.timestamp <= type(uint64).max, "timestamp overflow");
    uint256 vested = vestedAmount(uint64(block.timestamp));
    if (vested <= released) return 0;
    return vested - released;
  }

  function release() external {
    require(msg.sender == beneficiary, "not beneficiary");
    uint256 amount = releasable();
    require(amount > 0, "nothing to release");

    // Safety check: ensure released won't exceed totalAllocation
    require(released + amount <= totalAllocation, "release exceeds allocation");

    // Check contract balance
    uint256 balance = token.balanceOf(address(this));
    require(balance >= amount, "insufficient contract balance");

    released += amount;
    bool ok = token.transfer(beneficiary, amount);
    require(ok, "transfer failed");

    uint256 remaining = totalAllocation - released;
    emit Released(amount, released, remaining);
  }

  // Emergency withdraw: allows beneficiary to withdraw all remaining tokens
  // Should only be used in extreme cases (e.g., token contract issues)
  function emergencyWithdraw() external {
    require(msg.sender == beneficiary, "not beneficiary");
    uint256 balance = token.balanceOf(address(this));
    require(balance > 0, "no balance");

    // Mark as fully released to prevent further releases
    released = totalAllocation;

    bool ok = token.transfer(beneficiary, balance);
    require(ok, "transfer failed");
    emit Released(balance, released, 0);
  }

  // --- View functions ---

  function totalReleased() public view returns (uint256) {
    return released;
  }

  function remaining() public view returns (uint256) {
    return totalAllocation - released;
  }

  function isFullyVested() public view returns (bool) {
    require(block.timestamp <= type(uint64).max, "timestamp overflow");
    return uint64(block.timestamp) >= start + durationSeconds;
  }

  function vestingEndTime() public view returns (uint64) {
    return start + durationSeconds;
  }

  function cliffEndTime() public view returns (uint64) {
    return start + cliffSeconds;
  }
}

contracts/launch/LPTimeLock.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * LPTimeLock
 * A simple time-lock vault for ERC20 tokens (e.g. UniswapV2 LP tokens).
 *
 * Typical flow:
 * 1) Add liquidity -> receive LP tokens to your wallet
 * 2) Approve LPTimeLock to spend LP tokens
 * 3) Create lock with unlockTime (timestamp)
 * 4) Anyone can verify the lock on-chain; only beneficiary can withdraw after unlock.
 */

interface IERC20Lock {
  function transferFrom(address from, address to, uint256 amount) external returns (bool);
  function transfer(address to, uint256 amount) external returns (bool);
  function balanceOf(address account) external view returns (uint256);
}

contract LPTimeLock {
  struct Lock {
    address token;        // LP token address (ERC20)
    address owner;        // creator (can extend / transfer ownership)
    address beneficiary;  // receiver after unlock
    uint256 amount;       // locked amount
    uint256 unlockTime;   // unix timestamp
    bool withdrawn;       // state
  }

  uint256 public nextId = 1;
  mapping(uint256 => Lock) public locks;

  event LockCreated(
    uint256 indexed id,
    address indexed token,
    address indexed beneficiary,
    uint256 amount,
    uint256 unlockTime
  );
  event LockExtended(uint256 indexed id, uint256 oldUnlockTime, uint256 newUnlockTime);
  event LockOwnershipTransferred(uint256 indexed id, address indexed oldOwner, address indexed newOwner);
  event LockBeneficiaryUpdated(uint256 indexed id, address indexed oldBeneficiary, address indexed newBeneficiary);
  event Withdrawn(uint256 indexed id, address indexed beneficiary, uint256 amount);

  modifier onlyLockOwner(uint256 id) {
    require(locks[id].owner == msg.sender, "Not lock owner");
    _;
  }

  function createLock(
    address token,
    address beneficiary,
    uint256 amount,
    uint256 unlockTime
  ) external returns (uint256 id) {
    require(token != address(0), "token=0");
    require(beneficiary != address(0), "beneficiary=0");
    require(amount > 0, "amount=0");
    require(unlockTime > block.timestamp, "unlockTime must be future");

    id = nextId++;
    locks[id] = Lock({
      token: token,
      owner: msg.sender,
      beneficiary: beneficiary,
      amount: amount,
      unlockTime: unlockTime,
      withdrawn: false
    });

    bool ok = IERC20Lock(token).transferFrom(msg.sender, address(this), amount);
    require(ok, "transferFrom failed");

    emit LockCreated(id, token, beneficiary, amount, unlockTime);
  }

  function extendLock(uint256 id, uint256 newUnlockTime) external onlyLockOwner(id) {
    Lock storage l = locks[id];
    require(!l.withdrawn, "already withdrawn");
    require(newUnlockTime > l.unlockTime, "must extend");
    uint256 old = l.unlockTime;
    l.unlockTime = newUnlockTime;
    emit LockExtended(id, old, newUnlockTime);
  }

  function transferLockOwnership(uint256 id, address newOwner) external onlyLockOwner(id) {
    require(newOwner != address(0), "newOwner=0");
    Lock storage l = locks[id];
    require(!l.withdrawn, "already withdrawn");
    address old = l.owner;
    l.owner = newOwner;
    emit LockOwnershipTransferred(id, old, newOwner);
  }

  function updateBeneficiary(uint256 id, address newBeneficiary) external onlyLockOwner(id) {
    require(newBeneficiary != address(0), "newBeneficiary=0");
    Lock storage l = locks[id];
    require(!l.withdrawn, "already withdrawn");
    address old = l.beneficiary;
    l.beneficiary = newBeneficiary;
    emit LockBeneficiaryUpdated(id, old, newBeneficiary);
  }

  function withdraw(uint256 id) external {
    Lock storage l = locks[id];
    require(!l.withdrawn, "already withdrawn");
    require(msg.sender == l.beneficiary, "not beneficiary");
    require(block.timestamp >= l.unlockTime, "still locked");

    l.withdrawn = true;
    bool ok = IERC20Lock(l.token).transfer(l.beneficiary, l.amount);
    require(ok, "transfer failed");
    emit Withdrawn(id, l.beneficiary, l.amount);
  }

  function getLockStatus(uint256 id) external view returns (bool isLocked, uint256 remainingSeconds) {
    Lock memory l = locks[id];
    if (l.withdrawn) return (false, 0);
    if (block.timestamp >= l.unlockTime) return (false, 0);
    return (true, l.unlockTime - block.timestamp);
  }
}

contracts/launch/OZAdvancedLaunchToken.s.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * OZAdvancedLaunchToken (Uniswap V2 style)
 * OpenZeppelin-based ERC20 with:
 * - Buy/Sell fees (marketing / liquidity / burn) in BPS
 * - Anti-bot (dead blocks, max gas price)
 * - Limits (max tx, max wallet)
 * - Whitelist / Blacklist
 * - Trading toggle + auto pair create via UniswapV2 router
 * - Swap-back: swap fee tokens to ETH + add liquidity + send marketing ETH
 *
 * Notes:
 * - Targets Uniswap V2 / V2 forks (PancakeSwap V2 etc.)
 * - Uniswap V3 LP is NFT; not compatible with V2 LP lock flow
 */

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

interface IUniswapV2Factory {
  function createPair(address tokenA, address tokenB) external returns (address pair);
}

interface IUniswapV2Router02 {
  function factory() external view returns (address);
  function WETH() external view returns (address);
  function addLiquidityETH(
    address token,
    uint256 amountTokenDesired,
    uint256 amountTokenMin,
    uint256 amountETHMin,
    address to,
    uint256 deadline
  ) external payable returns (uint256 amountToken, uint256 amountETH, uint256 liquidity);

  function swapExactTokensForETHSupportingFeeOnTransferTokens(
    uint256 amountIn,
    uint256 amountOutMin,
    address[] calldata path,
    address to,
    uint256 deadline
  ) external;
}

contract OZAdvancedLaunchToken is ERC20, Ownable {
  struct FeeConfig {
    uint16 marketingBps;
    uint16 liquidityBps;
    uint16 burnBps;
    uint16 totalBps;
  }

  address public marketingWallet;
  address public constant BURN_ADDRESS = address(0x000000000000000000000000000000000000dEaD);

  // Uniswap V2
  IUniswapV2Router02 public uniswapV2Router;
  address public uniswapV2Pair;

  // trading
  bool public tradingEnabled;
  uint256 public launchBlock;

  // fees
  FeeConfig public buyFee;
  FeeConfig public sellFee;

  bool public swapEnabled = true;
  uint256 public swapTokensAtAmount;
  bool private _inSwap;

  // anti-bot / limits
  uint256 public maxGasPriceWei; // 0 disabled
  uint256 public deadBlocks; // 0 disabled
  bool public revertEarlyBuys = true;

  uint256 public maxTxAmount; // 0 disabled
  uint256 public maxWalletAmount; // 0 disabled

  mapping(address => bool) public isWhitelisted;
  mapping(address => bool) public isBlacklisted;
  mapping(address => bool) public isExcludedFromFees;
  mapping(address => bool) public isExcludedFromLimits;

  event RouterSet(address indexed router, address indexed pair);
  event TradingEnabled(uint256 indexed launchBlock, address indexed pair);
  event MarketingWalletSet(address indexed wallet);
  event FeesUpdated(string side, uint16 marketingBps, uint16 liquidityBps, uint16 burnBps, uint16 totalBps);
  event SwapSettingsUpdated(bool enabled, uint256 thresholdTokens);
  event LimitsUpdated(uint256 maxGasPriceWei, uint256 deadBlocks, bool revertEarlyBuys, uint256 maxTxAmount, uint256 maxWalletAmount);
  event AddressFlagsUpdated(address indexed account, bool whitelisted, bool blacklisted, bool excludedFees, bool excludedLimits);

  modifier swapping() {
    _inSwap = true;
    _;
    _inSwap = false;
  }

  constructor(
    address initialOwner,
    string memory tokenName,
    string memory tokenSymbol,
    uint256 initialSupplyRaw,
    address marketingWallet_
  ) ERC20(tokenName, tokenSymbol) Ownable(initialOwner) {
    require(marketingWallet_ != address(0), "marketing wallet = 0");
    marketingWallet = marketingWallet_;

    // default fees: buy 4%, sell 6%
    buyFee = _makeFee(200, 200, 0);
    sellFee = _makeFee(300, 300, 0);

    // default swap threshold: 0.01%
    swapTokensAtAmount = initialSupplyRaw / 10_000;

    // exclusions
    isExcludedFromFees[initialOwner] = true;
    isExcludedFromFees[address(this)] = true;
    isExcludedFromFees[marketingWallet_] = true;

    isExcludedFromLimits[initialOwner] = true;
    isExcludedFromLimits[address(this)] = true;
    isExcludedFromLimits[marketingWallet_] = true;

    // whitelist owner + contract for pre-launch setup
    isWhitelisted[initialOwner] = true;
    isWhitelisted[address(this)] = true;

    _mint(initialOwner, initialSupplyRaw);
  }

  receive() external payable {}

  // --- admin: router/pair/trading ---
  function setRouter(address router) external onlyOwner {
    require(router != address(0), "router=0");
    uniswapV2Router = IUniswapV2Router02(router);
    address pair = IUniswapV2Factory(uniswapV2Router.factory()).createPair(address(this), uniswapV2Router.WETH());
    uniswapV2Pair = pair;
    isExcludedFromLimits[pair] = true;
    emit RouterSet(router, pair);
  }

  function enableTrading() external onlyOwner {
    require(!tradingEnabled, "already enabled");
    require(uniswapV2Pair != address(0), "pair not set");
    tradingEnabled = true;
    launchBlock = block.number;
    emit TradingEnabled(launchBlock, uniswapV2Pair);
  }

  // --- admin: config ---
  function setMarketingWallet(address wallet) external onlyOwner {
    require(wallet != address(0), "wallet=0");
    marketingWallet = wallet;
    isExcludedFromFees[wallet] = true;
    isExcludedFromLimits[wallet] = true;
    emit MarketingWalletSet(wallet);
  }

  function setBuyFees(uint16 marketingBps, uint16 liquidityBps, uint16 burnBps) external onlyOwner {
    buyFee = _makeFee(marketingBps, liquidityBps, burnBps);
    emit FeesUpdated("buy", marketingBps, liquidityBps, burnBps, buyFee.totalBps);
  }

  function setSellFees(uint16 marketingBps, uint16 liquidityBps, uint16 burnBps) external onlyOwner {
    sellFee = _makeFee(marketingBps, liquidityBps, burnBps);
    emit FeesUpdated("sell", marketingBps, liquidityBps, burnBps, sellFee.totalBps);
  }

  function setSwapSettings(bool enabled, uint256 thresholdTokens) external onlyOwner {
    swapEnabled = enabled;
    swapTokensAtAmount = thresholdTokens;
    emit SwapSettingsUpdated(enabled, thresholdTokens);
  }

  function setLimits(
    uint256 maxGasPriceWei_,
    uint256 deadBlocks_,
    bool revertEarlyBuys_,
    uint256 maxTxAmount_,
    uint256 maxWalletAmount_
  ) external onlyOwner {
    maxGasPriceWei = maxGasPriceWei_;
    deadBlocks = deadBlocks_;
    revertEarlyBuys = revertEarlyBuys_;
    maxTxAmount = maxTxAmount_;
    maxWalletAmount = maxWalletAmount_;
    emit LimitsUpdated(maxGasPriceWei_, deadBlocks_, revertEarlyBuys_, maxTxAmount_, maxWalletAmount_);
  }

  function setAddressFlags(
    address account,
    bool whitelisted,
    bool blacklisted,
    bool excludedFees,
    bool excludedLimits
  ) external onlyOwner {
    isWhitelisted[account] = whitelisted;
    isBlacklisted[account] = blacklisted;
    isExcludedFromFees[account] = excludedFees;
    isExcludedFromLimits[account] = excludedLimits;
    emit AddressFlagsUpdated(account, whitelisted, blacklisted, excludedFees, excludedLimits);
  }

  // manual trigger (owner or marketing)
  function manualSwapBack() external {
    require(msg.sender == owner() || msg.sender == marketingWallet, "not allowed");
    _swapBack();
  }

  // --- ERC20 hook (OZ v5) ---
  function _update(address from, address to, uint256 amount) internal override {
    require(!isBlacklisted[from] && !isBlacklisted[to], "Blacklisted");

    // gas price limit only for pair trades
    if (maxGasPriceWei > 0 && (from == uniswapV2Pair || to == uniswapV2Pair)) {
      require(tx.gasprice <= maxGasPriceWei, "Gas price too high");
    }

    // trading gate
    if (!tradingEnabled) {
      // allow mint/burn and whitelisted transfers pre-launch
      if (from != address(0) && to != address(0)) {
        require(isWhitelisted[from] || isWhitelisted[to], "Trading not enabled");
      }
    }

    bool isBuy = (from == uniswapV2Pair && to != address(uniswapV2Router));
    bool isSell = (to == uniswapV2Pair);

    // anti-bot: dead blocks restrict buys
    if (tradingEnabled && deadBlocks > 0 && isBuy && !isWhitelisted[to]) {
      if (block.number < launchBlock + deadBlocks) {
        if (revertEarlyBuys) revert("AntiBot: early buy blocked");
      }
    }

    // limits
    if (!isExcludedFromLimits[from] && !isExcludedFromLimits[to]) {
      if (maxTxAmount > 0 && (isBuy || isSell)) {
        require(amount <= maxTxAmount, "Max tx exceeded");
      }
      if (maxWalletAmount > 0 && isBuy) {
        require(balanceOf(to) + amount <= maxWalletAmount, "Max wallet exceeded");
      }
    }

    // swap back before sell
    if (
      !_inSwap &&
      swapEnabled &&
      isSell &&
      address(uniswapV2Router) != address(0) &&
      uniswapV2Pair != address(0) &&
      swapTokensAtAmount > 0 &&
      balanceOf(address(this)) >= swapTokensAtAmount
    ) {
      _swapBack();
    }

    // fees only on buys/sells, and not during swap
    if (
      !_inSwap &&
      (isBuy || isSell) &&
      from != address(0) &&
      to != address(0) &&
      !isExcludedFromFees[from] &&
      !isExcludedFromFees[to]
    ) {
      FeeConfig memory fee = isBuy ? buyFee : sellFee;
      if (fee.totalBps > 0) {
        uint256 feeAmount = (amount * fee.totalBps) / 10_000;
        if (feeAmount > 0) {
          uint256 transferAmount = amount - feeAmount;

          // burn portion
          uint256 burnAmount = (feeAmount * fee.burnBps) / fee.totalBps;
          uint256 remainingFee = feeAmount - burnAmount;

          if (burnAmount > 0) {
            super._update(from, BURN_ADDRESS, burnAmount);
          }
          if (remainingFee > 0) {
            super._update(from, address(this), remainingFee);
          }

          super._update(from, to, transferAmount);
          return;
        }
      }
    }

    super._update(from, to, amount);
  }

  function _makeFee(uint16 marketingBps, uint16 liquidityBps, uint16 burnBps) internal pure returns (FeeConfig memory) {
    uint16 total = marketingBps + liquidityBps + burnBps;
    require(total <= 2_000, "Fee too high (max 20%)");
    return FeeConfig({
      marketingBps: marketingBps,
      liquidityBps: liquidityBps,
      burnBps: burnBps,
      totalBps: total
    });
  }

  function _swapBack() internal swapping {
    uint256 contractTokenBalance = balanceOf(address(this));
    if (contractTokenBalance == 0) return;
    if (address(uniswapV2Router) == address(0)) return;
    if (uniswapV2Pair == address(0)) return;

    // use sell fee weights as default ratio
    uint16 totalBps = sellFee.totalBps;
    if (totalBps == 0) return;

    uint256 liquidityTokens = (contractTokenBalance * sellFee.liquidityBps) / totalBps;
    uint256 marketingTokens = contractTokenBalance - liquidityTokens;

    uint256 tokensForLiquidityHalf = liquidityTokens / 2;
    uint256 tokensToSwapForEth = marketingTokens + (liquidityTokens - tokensForLiquidityHalf);

    if (tokensToSwapForEth == 0) return;

    _approve(address(this), address(uniswapV2Router), tokensToSwapForEth);

    uint256 ethBefore = address(this).balance;
    address[] memory path = new address[](2);
    path[0] = address(this);
    path[1] = uniswapV2Router.WETH();

    uniswapV2Router.swapExactTokensForETHSupportingFeeOnTransferTokens(
      tokensToSwapForEth,
      0,
      path,
      address(this),
      block.timestamp
    );

    uint256 ethGained = address(this).balance - ethBefore;
    if (ethGained == 0) return;

    uint256 ethForMarketing = 0;
    if (tokensToSwapForEth > 0) {
      ethForMarketing = (ethGained * marketingTokens) / tokensToSwapForEth;
    }
    uint256 ethForLiquidity = ethGained - ethForMarketing;

    if (ethForMarketing > 0 && marketingWallet != address(0)) {
      (bool ok, ) = marketingWallet.call{ value: ethForMarketing }("");
      ok;
    }

    if (tokensForLiquidityHalf > 0 && ethForLiquidity > 0) {
      _approve(address(this), address(uniswapV2Router), tokensForLiquidityHalf);
      uniswapV2Router.addLiquidityETH{ value: ethForLiquidity }(
        address(this),
        tokensForLiquidityHalf,
        0,
        0,
        owner(),
        block.timestamp
      );
    }
  }
}

contracts/launch/OZAdvancedLaunchTokenUp.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * OZAdvancedLaunchTokenUpgradeable (clone-friendly)
 * - Same logic as OZAdvancedLaunchToken, but uses initializer instead of constructor
 * - Intended to be deployed once as an implementation, then cloned via EIP-1167 minimal proxies
 */

import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC20/ERC20Upgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";

interface IUniswapV2FactoryUpgradeable {
  function createPair(address tokenA, address tokenB) external returns (address pair);
  function getPair(address tokenA, address tokenB) external view returns (address pair);
}

interface IUniswapV2Router02Upgradeable {
  function factory() external view returns (address);
  function WETH() external view returns (address);
  function addLiquidityETH(
    address token,
    uint256 amountTokenDesired,
    uint256 amountTokenMin,
    uint256 amountETHMin,
    address to,
    uint256 deadline
  ) external payable returns (uint256 amountToken, uint256 amountETH, uint256 liquidity);

  function swapExactTokensForETHSupportingFeeOnTransferTokens(
    uint256 amountIn,
    uint256 amountOutMin,
    address[] calldata path,
    address to,
    uint256 deadline
  ) external;
}

contract OZAdvancedLaunchTokenUpgradeable is Initializable, ERC20Upgradeable, OwnableUpgradeable {
  struct FeeConfig {
    uint16 marketingBps;
    uint16 liquidityBps;
    uint16 burnBps;
    uint16 totalBps;
  }

  address public marketingWallet;
  address public constant BURN_ADDRESS = address(0x000000000000000000000000000000000000dEaD);

  // Uniswap V2
  IUniswapV2Router02Upgradeable public uniswapV2Router;
  address public uniswapV2Pair;

  // trading
  bool public tradingEnabled;
  uint256 public launchBlock;

  // fees
  FeeConfig public buyFee;
  FeeConfig public sellFee;

  bool public swapEnabled;
  uint256 public swapTokensAtAmount;
  bool private _inSwap;

  // anti-bot / limits
  uint256 public maxGasPriceWei; // 0 disabled
  uint256 public deadBlocks; // 0 disabled
  bool public revertEarlyBuys;

  uint256 public maxTxAmount; // 0 disabled
  uint256 public maxWalletAmount; // 0 disabled

  mapping(address => bool) public isWhitelisted;
  mapping(address => bool) public isBlacklisted;
  mapping(address => bool) public isExcludedFromFees;
  mapping(address => bool) public isExcludedFromLimits;

  event RouterSet(address indexed router, address indexed pair);
  event TradingEnabled(uint256 indexed launchBlock, address indexed pair);
  event MarketingWalletSet(address indexed wallet);
  event FeesUpdated(string side, uint16 marketingBps, uint16 liquidityBps, uint16 burnBps, uint16 totalBps);
  event SwapSettingsUpdated(bool enabled, uint256 thresholdTokens);
  event LimitsUpdated(uint256 maxGasPriceWei, uint256 deadBlocks, bool revertEarlyBuys, uint256 maxTxAmount, uint256 maxWalletAmount);
  event AddressFlagsUpdated(address indexed account, bool whitelisted, bool blacklisted, bool excludedFees, bool excludedLimits);

  modifier swapping() {
    _inSwap = true;
    _;
    _inSwap = false;
  }

  function initialize(
    address initialOwner,
    string calldata tokenName,
    string calldata tokenSymbol,
    uint256 initialSupplyRaw,
    address marketingWallet_
  ) external initializer {
    require(initialOwner != address(0), "owner=0");
    require(marketingWallet_ != address(0), "marketing=0");
    require(initialSupplyRaw > 0, "supply=0");

    __ERC20_init(tokenName, tokenSymbol);
    __Ownable_init(initialOwner);

    marketingWallet = marketingWallet_;

    // defaults
    buyFee = _makeFee(200, 200, 0);
    sellFee = _makeFee(300, 300, 0);
    swapEnabled = true;
    revertEarlyBuys = true;
    swapTokensAtAmount = initialSupplyRaw / 10_000; // 0.01%

    // exclusions
    isExcludedFromFees[initialOwner] = true;
    isExcludedFromFees[address(this)] = true;
    isExcludedFromFees[marketingWallet_] = true;

    isExcludedFromLimits[initialOwner] = true;
    isExcludedFromLimits[address(this)] = true;
    isExcludedFromLimits[marketingWallet_] = true;

    // whitelist owner + contract for pre-launch setup
    isWhitelisted[initialOwner] = true;
    isWhitelisted[address(this)] = true;

    _mint(initialOwner, initialSupplyRaw);
  }

  receive() external payable {}

  // Emergency: withdraw stuck ETH (owner only)
  function emergencyWithdrawETH() external onlyOwner {
    (bool ok, ) = payable(owner()).call{ value: address(this).balance }("");
    require(ok, "ETH withdraw failed");
  }

  // --- admin: router/pair/trading ---
  function setRouter(address router) external onlyOwner {
    require(router != address(0), "router=0");
    uniswapV2Router = IUniswapV2Router02Upgradeable(router);
    address factory = uniswapV2Router.factory();
    address weth = uniswapV2Router.WETH();

    // Check if pair already exists
    address existingPair = IUniswapV2FactoryUpgradeable(factory).getPair(address(this), weth);
    address pair;
    if (existingPair != address(0)) {
      pair = existingPair;
    } else {
      pair = IUniswapV2FactoryUpgradeable(factory).createPair(address(this), weth);
    }

    require(pair != address(0), "pair creation failed");
    uniswapV2Pair = pair;
    isExcludedFromLimits[pair] = true;
    emit RouterSet(router, pair);
  }

  function enableTrading() external onlyOwner {
    require(!tradingEnabled, "already enabled");
    require(uniswapV2Pair != address(0), "pair not set");
    tradingEnabled = true;
    launchBlock = block.number;
    emit TradingEnabled(launchBlock, uniswapV2Pair);
  }

  // --- admin: config ---
  function setMarketingWallet(address wallet) external onlyOwner {
    require(wallet != address(0), "wallet=0");
    marketingWallet = wallet;
    isExcludedFromFees[wallet] = true;
    isExcludedFromLimits[wallet] = true;
    emit MarketingWalletSet(wallet);
  }

  function setBuyFees(uint16 marketingBps, uint16 liquidityBps, uint16 burnBps) external onlyOwner {
    buyFee = _makeFee(marketingBps, liquidityBps, burnBps);
    emit FeesUpdated("buy", marketingBps, liquidityBps, burnBps, buyFee.totalBps);
  }

  function setSellFees(uint16 marketingBps, uint16 liquidityBps, uint16 burnBps) external onlyOwner {
    sellFee = _makeFee(marketingBps, liquidityBps, burnBps);
    emit FeesUpdated("sell", marketingBps, liquidityBps, burnBps, sellFee.totalBps);
  }

  function setSwapSettings(bool enabled, uint256 thresholdTokens) external onlyOwner {
    swapEnabled = enabled;
    swapTokensAtAmount = thresholdTokens;
    emit SwapSettingsUpdated(enabled, thresholdTokens);
  }

  function setLimits(
    uint256 maxGasPriceWei_,
    uint256 deadBlocks_,
    bool revertEarlyBuys_,
    uint256 maxTxAmount_,
    uint256 maxWalletAmount_
  ) external onlyOwner {
    maxGasPriceWei = maxGasPriceWei_;
    deadBlocks = deadBlocks_;
    revertEarlyBuys = revertEarlyBuys_;
    maxTxAmount = maxTxAmount_;
    maxWalletAmount = maxWalletAmount_;
    emit LimitsUpdated(maxGasPriceWei_, deadBlocks_, revertEarlyBuys_, maxTxAmount_, maxWalletAmount_);
  }

  function setAddressFlags(
    address account,
    bool whitelisted,
    bool blacklisted,
    bool excludedFees,
    bool excludedLimits
  ) external onlyOwner {
    isWhitelisted[account] = whitelisted;
    isBlacklisted[account] = blacklisted;
    isExcludedFromFees[account] = excludedFees;
    isExcludedFromLimits[account] = excludedLimits;
    emit AddressFlagsUpdated(account, whitelisted, blacklisted, excludedFees, excludedLimits);
  }

  // manual trigger (owner only)
  function manualSwapBack() external onlyOwner {
    _swapBack();
  }

  // --- ERC20 hook (OZ v5) ---
  function _update(address from, address to, uint256 amount) internal override {
    require(!isBlacklisted[from] && !isBlacklisted[to], "Blacklisted");

    // gas price limit only for pair trades
    if (maxGasPriceWei > 0 && (from == uniswapV2Pair || to == uniswapV2Pair)) {
      require(tx.gasprice <= maxGasPriceWei, "Gas price too high");
    }

    // trading gate
    if (!tradingEnabled) {
      // allow mint/burn and whitelisted transfers pre-launch
      if (from != address(0) && to != address(0)) {
        require(isWhitelisted[from] || isWhitelisted[to], "Trading not enabled");
      }
    }

    bool isBuy = (from == uniswapV2Pair && to != address(uniswapV2Router));
    bool isSell = (to == uniswapV2Pair);

    // anti-bot: dead blocks restrict buys
    if (tradingEnabled && deadBlocks > 0 && isBuy && !isWhitelisted[to]) {
      if (block.number < launchBlock + deadBlocks) {
        if (revertEarlyBuys) revert("AntiBot: early buy blocked");
      }
    }

    // limits
    if (!isExcludedFromLimits[from] && !isExcludedFromLimits[to]) {
      if (maxTxAmount > 0 && (isBuy || isSell)) {
        require(amount <= maxTxAmount, "Max tx exceeded");
      }
      if (maxWalletAmount > 0 && isBuy) {
        require(balanceOf(to) + amount <= maxWalletAmount, "Max wallet exceeded");
      }
    }

    // swap back before sell
    if (
      !_inSwap &&
      swapEnabled &&
      isSell &&
      address(uniswapV2Router) != address(0) &&
      uniswapV2Pair != address(0) &&
      swapTokensAtAmount > 0 &&
      balanceOf(address(this)) >= swapTokensAtAmount
    ) {
      _swapBack();
    }

    // fees only on buys/sells, and not during swap
    if (
      !_inSwap &&
      (isBuy || isSell) &&
      from != address(0) &&
      to != address(0) &&
      !isExcludedFromFees[from] &&
      !isExcludedFromFees[to]
    ) {
      FeeConfig memory fee = isBuy ? buyFee : sellFee;
      if (fee.totalBps > 0) {
        uint256 feeAmount = (amount * fee.totalBps) / 10_000;
        if (feeAmount > 0) {
          uint256 transferAmount = amount - feeAmount;

          // burn portion
          uint256 burnAmount = (feeAmount * fee.burnBps) / fee.totalBps;
          uint256 remainingFee = feeAmount - burnAmount;

          if (burnAmount > 0) {
            super._update(from, BURN_ADDRESS, burnAmount);
          }
          if (remainingFee > 0) {
            super._update(from, address(this), remainingFee);
          }

          super._update(from, to, transferAmount);
          return;
        }
      }
    }

    super._update(from, to, amount);
  }

  function _makeFee(uint16 marketingBps, uint16 liquidityBps, uint16 burnBps) internal pure returns (FeeConfig memory) {
    uint16 total = marketingBps + liquidityBps + burnBps;
    require(total <= 2_000, "Fee too high (max 20%)");
    return FeeConfig({ marketingBps: marketingBps, liquidityBps: liquidityBps, burnBps: burnBps, totalBps: total });
  }

  function _swapBack() internal swapping {
    uint256 contractTokenBalance = balanceOf(address(this));
    if (contractTokenBalance == 0) return;
    if (address(uniswapV2Router) == address(0)) return;
    if (uniswapV2Pair == address(0)) return;

    // use sell fee weights as default ratio
    uint16 totalBps = sellFee.totalBps;
    if (totalBps == 0) return;

    uint256 liquidityTokens = (contractTokenBalance * sellFee.liquidityBps) / totalBps;
    uint256 marketingTokens = contractTokenBalance - liquidityTokens;

    uint256 tokensForLiquidityHalf = liquidityTokens / 2;
    uint256 tokensToSwapForEth = marketingTokens + (liquidityTokens - tokensForLiquidityHalf);
    if (tokensToSwapForEth == 0) return;

    _approve(address(this), address(uniswapV2Router), tokensToSwapForEth);

    uint256 ethBefore = address(this).balance;
    address[] memory path = new address[](2);
    path[0] = address(this);
    path[1] = uniswapV2Router.WETH();

    uniswapV2Router.swapExactTokensForETHSupportingFeeOnTransferTokens(tokensToSwapForEth, 0, path, address(this), block.timestamp);

    uint256 ethGained = address(this).balance - ethBefore;
    if (ethGained == 0) return;

    uint256 ethForMarketing = 0;
    if (tokensToSwapForEth > 0) {
      ethForMarketing = (ethGained * marketingTokens) / tokensToSwapForEth;
    }
    uint256 ethForLiquidity = ethGained - ethForMarketing;

    if (ethForMarketing > 0 && marketingWallet != address(0)) {
      (bool ok, ) = marketingWallet.call{ value: ethForMarketing }("");
      require(ok, "ETH transfer failed");
    }

    if (tokensForLiquidityHalf > 0 && ethForLiquidity > 0) {
      _approve(address(this), address(uniswapV2Router), tokensForLiquidityHalf);
      uniswapV2Router.addLiquidityETH{ value: ethForLiquidity }(address(this), tokensForLiquidityHalf, 0, 0, owner(), block.timestamp);
    }
  }
}

contracts/launch/TokenFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * TokenFactory (OZ-based)
 *
 * Why:
 * - Frontend should not ship bytecode. Users call a pre-deployed factory to deploy a token in 1 tx.
 * - This factory deploys OZAdvancedLaunchToken, optionally configures fees/limits, then transfers ownership to user.
 */

import "@openzeppelin/contracts/proxy/Clones.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

import "./OZAdvancedLaunchTokenUpgradeable.sol";
import "./LinearVestingVaultUpgradeable.sol";

contract TokenFactory is ReentrancyGuard {
  using SafeERC20 for IERC20;
  event TokenCreated(address indexed creator, address indexed token);
  event TokenDistributed(address indexed token, address indexed to, uint256 amount);
  event VestingCreated(address indexed token, address indexed vault, address indexed beneficiary, uint256 amount);
  event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);
  event FeesUpdated(
    uint256 oldBasicFeeWei,
    uint256 oldDistributionFeeWei,
    uint256 oldVestingFeeWei,
    uint256 newBasicFeeWei,
    uint256 newDistributionFeeWei,
    uint256 newVestingFeeWei
  );
  event FeesWithdrawn(address indexed to, uint256 amountWei);

  address public immutable tokenImplementation;
  address public immutable vestingImplementation;

  address public owner;
  // Tiered pricing (native token / ETH on EVM chains)
  uint256 public basicFeeWei;         // createToken
  uint256 public distributionFeeWei;  // createTokenWithDistribution
  uint256 public vestingFeeWei;       // createTokenWithDistributionAndVesting

  modifier onlyOwner() {
    require(msg.sender == owner, "not owner");
    _;
  }

  constructor(address tokenImplementation_, address vestingImplementation_) {
    require(tokenImplementation_ != address(0), "tokenImpl=0");
    require(vestingImplementation_ != address(0), "vestingImpl=0");
    tokenImplementation = tokenImplementation_;
    vestingImplementation = vestingImplementation_;
    owner = msg.sender;
    emit OwnershipTransferred(address(0), msg.sender);

    // Defaults:
    // - basic: 0.0005 ETH
    // - distribution: 0.003 ETH
    // - vesting: 0.005 ETH
    basicFeeWei = 0.0005 ether;
    distributionFeeWei = 0.003 ether;
    vestingFeeWei = 0.005 ether;
  }

  function transferOwnership(address newOwner) external onlyOwner {
    require(newOwner != address(0), "owner=0");
    address prev = owner;
    owner = newOwner;
    emit OwnershipTransferred(prev, newOwner);
  }

  function setFeesWei(uint256 newBasicFeeWei, uint256 newDistributionFeeWei, uint256 newVestingFeeWei) external onlyOwner {
    // Set reasonable upper limits (1 ETH) to prevent excessive fees
    require(newBasicFeeWei <= 1 ether, "basic fee too high");
    require(newDistributionFeeWei <= 1 ether, "distribution fee too high");
    require(newVestingFeeWei <= 1 ether, "vesting fee too high");

    uint256 oldBasic = basicFeeWei;
    uint256 oldDistribution = distributionFeeWei;
    uint256 oldVesting = vestingFeeWei;
    basicFeeWei = newBasicFeeWei;
    distributionFeeWei = newDistributionFeeWei;
    vestingFeeWei = newVestingFeeWei;
    emit FeesUpdated(oldBasic, oldDistribution, oldVesting, newBasicFeeWei, newDistributionFeeWei, newVestingFeeWei);
  }

  function withdrawFees(address payable to, uint256 amountWei) external onlyOwner nonReentrant {
    if (to == address(0)) to = payable(owner);
    uint256 amount = amountWei == 0 ? address(this).balance : amountWei;
    require(amount <= address(this).balance, "insufficient balance");

    // Emit event before external call (CEI pattern)
    emit FeesWithdrawn(to, amount);

    // External call at the end
    (bool ok, ) = to.call{ value: amount }("");
    require(ok, "withdraw failed");
  }

  function _requireFeePaid(uint256 feeWei) private view {
    if (feeWei == 0) {
      require(msg.value == 0, "no fee required");
    } else {
      require(msg.value == feeWei, "bad fee");
    }
  }

  struct TokenConfig {
    string name;
    string symbol;
    uint256 totalSupplyRaw;
    address marketingWallet;
    Fees fees;
    Limits limits;
  }

  struct Fees {
    uint16 buyMarketingBps;
    uint16 buyLiquidityBps;
    uint16 buyBurnBps;
    uint16 sellMarketingBps;
    uint16 sellLiquidityBps;
    uint16 sellBurnBps;
  }

  struct Limits {
    uint256 maxGasPriceWei; // 0 disabled
    uint256 deadBlocks;     // 0 disabled
    bool revertEarlyBuys;
    uint256 maxTxAmount;    // 0 disabled (raw)
    uint256 maxWalletAmount;// 0 disabled (raw)
  }

  struct Vesting {
    address beneficiary;
    uint64 start;
    uint64 cliffSeconds;
    uint64 durationSeconds;
    uint256 amount; // raw units
  }

  function _deployToken(TokenConfig calldata cfg) private returns (OZAdvancedLaunchTokenUpgradeable token, address tokenAddr) {
    address marketing = cfg.marketingWallet;
    if (marketing == address(0)) {
      // If user doesn't specify a marketing wallet, default to the token creator.
      marketing = msg.sender;
    }
    tokenAddr = Clones.clone(tokenImplementation);
    token = OZAdvancedLaunchTokenUpgradeable(payable(tokenAddr));
    token.initialize(address(this), cfg.name, cfg.symbol, cfg.totalSupplyRaw, marketing);

    // optional config before ownership transfer (factory is owner at this moment)
    token.setBuyFees(cfg.fees.buyMarketingBps, cfg.fees.buyLiquidityBps, cfg.fees.buyBurnBps);
    token.setSellFees(cfg.fees.sellMarketingBps, cfg.fees.sellLiquidityBps, cfg.fees.sellBurnBps);
    token.setLimits(
      cfg.limits.maxGasPriceWei,
      cfg.limits.deadBlocks,
      cfg.limits.revertEarlyBuys,
      cfg.limits.maxTxAmount,
      cfg.limits.maxWalletAmount
    );
  }

  function _deployVesting(address tokenAddr, Vesting calldata v) private returns (address vaultAddr) {
    vaultAddr = Clones.clone(vestingImplementation);
    LinearVestingVaultUpgradeable(vaultAddr).initialize(
      tokenAddr,
      v.beneficiary,
      v.start,
      v.cliffSeconds,
      v.durationSeconds,
      v.amount
    );
  }

  function _validateRecipientsAndSum(
    uint256 totalSupplyRaw,
    address[] calldata recipients,
    uint256[] calldata amounts
  ) private pure returns (uint256 sum) {
    require(recipients.length == amounts.length, "length mismatch");
    require(recipients.length <= 100, "too many recipients"); // Prevent gas exhaustion
    for (uint256 i = 0; i < recipients.length; i++) {
      require(recipients[i] != address(0), "recipient=0");
      uint256 amt = amounts[i];
      if (amt == 0) continue;
      sum += amt;
    }
    require(sum <= totalSupplyRaw, "distribution > supply");
  }

  function _validateRecipientsVestingsAndSum(
    uint256 totalSupplyRaw,
    address[] calldata recipients,
    uint256[] calldata amounts,
    Vesting[] calldata vestings
  ) private pure returns (uint256 sum) {
    sum = _validateRecipientsAndSum(totalSupplyRaw, recipients, amounts);
    require(vestings.length <= 50, "too many vestings"); // Prevent gas exhaustion
    for (uint256 j = 0; j < vestings.length; j++) {
      Vesting calldata v = vestings[j];
      require(v.beneficiary != address(0), "beneficiary=0");
      require(v.amount > 0, "vesting amount=0");
      sum += v.amount;
    }
    require(sum <= totalSupplyRaw, "distribution > supply");
  }

  function createToken(TokenConfig calldata cfg) external payable returns (address tokenAddr) {
    _requireFeePaid(basicFeeWei);
    require(cfg.totalSupplyRaw > 0, "supply=0");

    OZAdvancedLaunchTokenUpgradeable token;
    (token, tokenAddr) = _deployToken(cfg);

    token.transferOwnership(msg.sender);

    // transfer all minted tokens to user (factory is initial owner & receiver)
    uint256 bal = token.balanceOf(address(this));
    if (bal > 0) {
      IERC20(address(token)).safeTransfer(msg.sender, bal);
    }

    emit TokenCreated(msg.sender, tokenAddr);
  }

  /**
   * Create token and distribute initial supply to multiple recipients.
   *
   * - `recipients` and `amounts` must have same length.
   * - Sum(amounts) must be <= totalSupplyRaw.
   * - Remaining supply is transferred to msg.sender.
   */
  function createTokenWithDistribution(
    TokenConfig calldata cfg,
    address[] calldata recipients,
    uint256[] calldata amounts
  ) external payable returns (address tokenAddr) {
    _requireFeePaid(distributionFeeWei);
    require(cfg.totalSupplyRaw > 0, "supply=0");
    _validateRecipientsAndSum(cfg.totalSupplyRaw, recipients, amounts);

    OZAdvancedLaunchTokenUpgradeable token;
    (token, tokenAddr) = _deployToken(cfg);

    // distribute from factory-held balance
    for (uint256 i = 0; i < recipients.length; i++) {
      uint256 amt = amounts[i];
      if (amt == 0) continue;
      IERC20(address(token)).safeTransfer(recipients[i], amt);
      emit TokenDistributed(tokenAddr, recipients[i], amt);
    }

    // remaining supply to creator
    uint256 remaining = token.balanceOf(address(this));
    if (remaining > 0) {
      IERC20(address(token)).safeTransfer(msg.sender, remaining);
      emit TokenDistributed(tokenAddr, msg.sender, remaining);
    }

    token.transferOwnership(msg.sender);
    emit TokenCreated(msg.sender, tokenAddr);
  }

  /**
   * Create token, distribute some immediately, and vest some via LinearVestingVault(s).
   *
   * - Immediate: `recipients` + `amounts`
   * - Vesting: `vestings` (each entry deploys a new vault)
   * - Total of immediate + vesting must be <= totalSupplyRaw
   * - Remaining goes to msg.sender
   */
  function createTokenWithDistributionAndVesting(
    TokenConfig calldata cfg,
    address[] calldata recipients,
    uint256[] calldata amounts,
    Vesting[] calldata vestings
  ) external payable returns (address tokenAddr) {
    _requireFeePaid(vestingFeeWei);
    require(cfg.totalSupplyRaw > 0, "supply=0");
    _validateRecipientsVestingsAndSum(cfg.totalSupplyRaw, recipients, amounts, vestings);

    OZAdvancedLaunchTokenUpgradeable token;
    (token, tokenAddr) = _deployToken(cfg);

    // immediate distribution
    for (uint256 i = 0; i < recipients.length; i++) {
      uint256 amt = amounts[i];
      if (amt == 0) continue;
      IERC20(address(token)).safeTransfer(recipients[i], amt);
      emit TokenDistributed(tokenAddr, recipients[i], amt);
    }

    // vesting distribution
    for (uint256 j = 0; j < vestings.length; j++) {
      Vesting calldata v = vestings[j];
      address vaultAddr = _deployVesting(tokenAddr, v);
      IERC20(address(token)).safeTransfer(vaultAddr, v.amount);
      emit VestingCreated(tokenAddr, vaultAddr, v.beneficiary, v.amount);
    }

    // remaining to creator
    uint256 remaining = token.balanceOf(address(this));
    if (remaining > 0) {
      IERC20(address(token)).safeTransfer(msg.sender, remaining);
      emit TokenDistributed(tokenAddr, msg.sender, remaining);
    }

    token.transferOwnership(msg.sender);
    emit TokenCreated(msg.sender, tokenAddr);
  }
}

